// ═══════════════════════════════════════════════════════════════
// NODO 1 — Resolver Input
// ═══════════════════════════════════════════════════════════════
// ⚠️  SHEETS_ID — reemplazar __SHEETS_ID__ con el ID real del Sheets
// Actualizar aquí y en todos los nodos Google Sheets si cambia.
// Valor actual: __SHEETS_ID__
//
// ⚠️  CREDENCIALES
// credential id (__CREDENTIAL_ID__) específico de esta instancia.
// Sanitizar antes de subir a GitHub:
//   "id" en cada bloque credentials → "__CREDENTIAL_ID__"
//   SHEETS_ID → "__SHEETS_ID__"
// ═══════════════════════════════════════════════════════════════

const SHEETS_ID  = '__SHEETS_ID__'; // __ENTORNO__
const DIAS_CICLO = 60;

const input = $input.first()?.json ?? {};

function generarFechas(dias) {
  const fechas = [];
  const hoy = new Date();
  hoy.setUTCHours(0, 0, 0, 0);
  for (let i = 0; i < dias; i++) {
    const d = new Date(hoy);
    d.setUTCDate(hoy.getUTCDate() + i);
    fechas.push(d.toISOString().split('T')[0]);
  }
  return fechas;
}

const id_cabanas_input = (Array.isArray(input.id_cabanas) && input.id_cabanas.length > 0)
  ? input.id_cabanas : [];

const fechas = (Array.isArray(input.fechas) && input.fechas.length > 0)
  ? input.fechas : generarFechas(DIAS_CICLO);

const source_event = input.source_event ?? 'recalculo_manual';

return [{
  json: {
    SHEETS_ID,
    id_cabanas_input,
    fechas,
    source_event,
    scope: id_cabanas_input.length === 0 ? 'todas_las_cabanas' : 'cabanas_especificas',
    total_fechas: fechas.length,
    ts_inicio: new Date().toISOString()
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO 2 — Consolidar Contexto
// ═══════════════════════════════════════════════════════════════
// Cada nodo Aggregate colapsa N items en 1 item con campo 'data'
// que contiene un array con todos los objetos de esa hoja.
// Así la cadena siempre pasa exactamente 1 item de nodo en nodo.
//
// Acceso: $('Agg CABAÑAS').first().json.data → array de cabañas
//
// HOJAS VACÍAS:
// Leer RESERVAS/PRE_RESERVAS/BLOQUEOS tienen alwaysOutputData:true
// → entregan {} si vacías → Aggregate lo colapsa en [{}]
// → .filter() descarta el {} vacío → resultado: []
// ═══════════════════════════════════════════════════════════════

const inputData   = $('Resolver Input').first().json;
const cabanas     = $('Agg CABAÑAS').first().json.data     ?? [];
const configRows  = $('Agg CONFIG').first().json.data      ?? [];
const temporadas  = $('Agg TEMPORADAS').first().json.data  ?? [];
const feriados    = $('Agg FERIADOS').first().json.data    ?? [];

// Hojas opcionales: descartar el {} vacío de alwaysOutputData
const reservas    = ($('Agg RESERVAS').first().json.data    ?? [])
  .filter(r => r && Object.keys(r).length > 0);
const prereservas = ($('Agg PRE_RESERVAS').first().json.data ?? [])
  .filter(p => p && Object.keys(p).length > 0);
const bloqueos    = ($('Agg BLOQUEOS').first().json.data    ?? [])
  .filter(b => b && Object.keys(b).length > 0);

// CONFIGURACION_GENERAL → objeto plano para lookup O(1)
const config = {};
for (const row of configRows) {
  if (row.clave && String(row.clave).trim() !== '') {
    config[String(row.clave).trim()] = String(row.valor ?? '').trim();
  }
}

// Resolver qué cabañas procesar
let cabanas_a_procesar = cabanas;
if (inputData.id_cabanas_input && inputData.id_cabanas_input.length > 0) {
  const idsSet = new Set(inputData.id_cabanas_input.map(String));
  cabanas_a_procesar = cabanas.filter(c => idsSet.has(String(c.id_cabana)));
}

// toYMD: normaliza cualquier valor de fecha a YYYY-MM-DD
function toYMD(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) {
    if (isNaN(val.getTime())) return null;
    return val.toISOString().split('T')[0];
  }
  if (typeof val === 'number') {
    const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
    return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
  }
  const s = String(val).trim();
  if (!s) return null;
  const p = s.split('T')[0];
  if (/^\d{4}-\d{2}-\d{2}$/.test(p)) return p;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
}

// feriadosMap: 'YYYY-MM-DD' → 'feriado' | 'ano_nuevo'
const feriadosMap = {};
for (const f of feriados) {
  const fechaKey = toYMD(f.fecha);
  if (fechaKey) {
    const tipo = String(f.tipo ?? '').trim().toLowerCase();
    feriadosMap[fechaKey] = tipo === 'ano_nuevo' ? 'ano_nuevo' : 'feriado';
  }
}

return [{
  json: {
    inputData,
    cabanas_a_procesar,
    config,
    temporadas,
    feriadosMap,
    reservas,
    prereservas,
    bloqueos,
    ts_inicio: inputData.ts_inicio,
    debug: {
      n_cabanas:     cabanas_a_procesar.length,
      n_config_keys: Object.keys(config).length,
      n_temporadas:  temporadas.length,
      n_feriados:    feriados.length,
      n_reservas:    reservas.length,
      n_prereservas: prereservas.length,
      n_bloqueos:    bloqueos.length
    }
  }
}];

// ═══════════════════════════════════════════════════════════════
// NODO 3 — Motor de Cálculo
// ═══════════════════════════════════════════════════════════════
// Genera las filas de DISPONIBILIDAD_CACHE para el producto
// cartesiano (cabañas × fechas).
//
// ALCANCE EXPLÍCITO v8:
// ✅ PASO 1  — Movimientos operativos (checkout/checkin del día)
// ✅ PASO 2  — RESERVAS ocupando la noche (intervalo semiabierto)
// ✅ PASO 3  — BLOQUEOS activos (RESERVA prevalece sobre BLOQUEO)
// ✅ PASO 4  — PRE_RESERVAS vigentes
// ✅ PASO 4B — Estado final (disponible / checkout_disponible)
// ✅ Horarios base desde CONFIGURACION_GENERAL
// ✅ toYMD() y fechaIgual() para comparaciones normalizadas
// ✅ tipo_dia por tabla de noches operativa
// ✅ FERIADOS con distinción feriado vs ano_nuevo
// ✅ temporada inferida de TEMPORADAS
// ✅ minimo_noches desde CONFIGURACION_GENERAL
//
// TIPO_DIA — tabla de noches (afecta pricing):
//   dom → semana | lun → semana | mar → semana
//   mié → semana | jue → semana
//   vie → finde  | sáb → finde
//   FERIADOS.tipo = 'ano_nuevo'        → 'ano_nuevo'  (precedencia)
//   FERIADOS.tipo = 'nacional'/'local' → 'feriado'    (precedencia)
//
// FUERA DE ALCANCE en v8:
// ❌ OVERRIDES_OPERATIVOS
// ❌ Escalonamiento automático de check-in
// ❌ es_ultimo_dia_bloque real (FALSE fijo)
// ❌ WhatsApp, pagos, pre-reservas automáticas, bot
// ═══════════════════════════════════════════════════════════════

const ctx = $input.first().json;
const { inputData, cabanas_a_procesar, config, temporadas, feriadosMap, reservas, prereservas, bloqueos } = ctx;
const fechas = inputData.fechas;
const ahora  = new Date();

// ── toYMD ────────────────────────────────────────────────────
function toYMD(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) {
    if (isNaN(val.getTime())) return null;
    return val.toISOString().split('T')[0];
  }
  if (typeof val === 'number') {
    const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
    return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
  }
  const s = String(val).trim();
  if (!s) return null;
  const p = s.split('T')[0];
  if (/^\d{4}-\d{2}-\d{2}$/.test(p)) return p;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d.toISOString().split('T')[0];
}

// ── parseTimestamp ────────────────────────────────────────────
function parseTimestamp(val) {
  if (!val && val !== 0) return null;
  if (val instanceof Date) return isNaN(val.getTime()) ? null : val;
  if (typeof val === 'number') {
    if (val < 200000) {
      const d = new Date(Date.UTC(1899, 11, 30) + val * 86400000);
      return isNaN(d.getTime()) ? null : d;
    }
    const d = new Date(val);
    return isNaN(d.getTime()) ? null : d;
  }
  const s = String(val).trim();
  if (!s) return null;
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

// ── fechaIgual ────────────────────────────────────────────────
function fechaIgual(a, b) {
  const ya = toYMD(a), yb = toYMD(b);
  if (!ya || !yb) return false;
  return ya === yb;
}

// ── Comparaciones de rango ────────────────────────────────────
function parseFechaMs(val) {
  const ymd = toYMD(val);
  if (!ymd) return null;
  const [y, m, d] = ymd.split('-').map(Number);
  return Date.UTC(y, m - 1, d, 12, 0, 0);
}
function fechaLte(a, b) {
  const ma = parseFechaMs(a), mb = parseFechaMs(b);
  if (ma === null || mb === null) return false;
  return ma <= mb;
}
function fechaGt(a, b) {
  const ma = parseFechaMs(a), mb = parseFechaMs(b);
  if (ma === null || mb === null) return false;
  return ma > mb;
}

// ── Helpers de negocio ────────────────────────────────────────
function getDiaSemana(fechaStr) {
  const ymd = toYMD(fechaStr);
  if (!ymd) return -1;
  const [y, m, d] = ymd.split('-').map(Number);
  return new Date(Date.UTC(y, m - 1, d, 12, 0, 0)).getUTCDay();
}

function getTipoDia(fechaStr, feriadosMap) {
  const ymd = toYMD(fechaStr);
  if (ymd && feriadosMap[ymd]) return feriadosMap[ymd];
  const dow = getDiaSemana(fechaStr);
  if (dow === 5 || dow === 6) return 'finde';
  return 'semana';
}

function getTemporada(fechaStr, temporadas) {
  const ms = parseFechaMs(fechaStr);
  if (ms === null) return 'media';
  for (const t of temporadas) {
    const msDesde = parseFechaMs(t.fecha_desde);
    const msHasta = parseFechaMs(t.fecha_hasta);
    if (msDesde === null || msHasta === null) continue;
    if (ms >= msDesde && ms <= msHasta) {
      const mult = parseFloat(String(t.multiplicador));
      if (isNaN(mult)) return 'media';
      if (mult > 1.0) return 'alta';
      if (mult < 1.0) return 'baja';
      return 'media';
    }
  }
  return 'media';
}

function getHoraCheckinBase(fechaStr, config) {
  if (getDiaSemana(fechaStr) === 0) return config.hora_checkin_domingo ?? '18:00';
  return config.hora_checkin_default ?? '13:00';
}

function getMinNoches(config) {
  const val = parseInt(String(config.minimo_noches ?? '1'), 10);
  return isNaN(val) ? 1 : val;
}

function normalizarBooleano(val) {
  if (val === true || val === 1) return true;
  if (typeof val === 'string') return val.trim().toUpperCase() === 'TRUE' || val.trim() === '1';
  return false;
}

// ── Motor principal ───────────────────────────────────────────
const filasCache = [];
const warnings   = [];

for (const cabana of cabanas_a_procesar) {
  const id_cabana = parseInt(String(cabana.id_cabana), 10);

  for (const fecha of fechas) {

    let estado               = null;
    let id_reserva_activa    = '';
    let id_prereserva_activa = '';
    let tiene_checkout       = false;
    let id_reserva_checkout  = '';
    let tiene_checkin        = false;
    let id_reserva_checkin   = '';

    // PASO 1: Movimientos operativos del día
    const reservaConCheckout = reservas.find(r =>
      parseInt(String(r.id_cabana), 10) === id_cabana &&
      ['confirmada', 'activa'].includes(String(r.estado ?? '')) &&
      fechaIgual(r.fecha_checkout, fecha)
    );
    if (reservaConCheckout) {
      tiene_checkout      = true;
      id_reserva_checkout = String(reservaConCheckout.id_reserva);
    }

    const reservaConCheckin = reservas.find(r =>
      parseInt(String(r.id_cabana), 10) === id_cabana &&
      ['confirmada', 'activa'].includes(String(r.estado ?? '')) &&
      fechaIgual(r.fecha_checkin, fecha)
    );
    if (reservaConCheckin) {
      tiene_checkin      = true;
      id_reserva_checkin = String(reservaConCheckin.id_reserva);
    }

    // PASO 2: ¿Reserva ocupando la noche? [fecha_checkin, fecha_checkout)
    const reservaOcupando = reservas.find(r =>
      parseInt(String(r.id_cabana), 10) === id_cabana &&
      ['confirmada', 'activa'].includes(String(r.estado ?? '')) &&
      fechaLte(r.fecha_checkin, fecha) &&
      fechaGt(r.fecha_checkout, fecha)
    );
    if (reservaOcupando) {
      estado            = 'ocupada';
      id_reserva_activa = String(reservaOcupando.id_reserva);
    }

    // PASO 3: BLOQUEOS activos
    const bloqueoAplicable = bloqueos.find(b => {
      const aplicaCabana =
        !b.id_cabana ||
        String(b.id_cabana).trim() === '' ||
        parseInt(String(b.id_cabana), 10) === id_cabana;
      const activo     = normalizarBooleano(b.activo);
      const rangoFecha = fechaLte(b.fecha_desde, fecha) && fechaGt(b.fecha_hasta, fecha);
      return aplicaCabana && activo && rangoFecha;
    });

    if (bloqueoAplicable) {
      if (estado === 'ocupada') {
        warnings.push({
          nivel: 'warning', id_cabana, fecha,
          detalle: `Conflicto BLOQUEO+RESERVA. id_cabana: ${id_cabana}, fecha: ${fecha}`
        });
      } else {
        const prereservaBajoBloqueo = prereservas.find(p => {
          const aplicaCabanaPR = parseInt(String(p.id_cabana), 10) === id_cabana;
          const estadoPR       = String(p.estado ?? '') === 'pendiente_pago';
          const expiraTs       = parseTimestamp(p.expira_en);
          const noVencida      = expiraTs ? expiraTs > ahora : false;
          const rangoFechaPR   = fechaLte(p.fecha_in, fecha) && fechaGt(p.fecha_out, fecha);
          return aplicaCabanaPR && estadoPR && noVencida && rangoFechaPR;
        });
        estado = 'bloqueada';
        if (prereservaBajoBloqueo) {
          id_prereserva_activa = String(prereservaBajoBloqueo.id_prereserva);
          warnings.push({
            nivel: 'warning', id_cabana, fecha,
            detalle: `Conflicto BLOQUEO+PRERESERVA. id_cabana: ${id_cabana}, fecha: ${fecha}`
          });
        }
      }
    }

    // PASO 4: PRE_RESERVAS vigentes
    if (!estado) {
      const prereservaVigente = prereservas.find(p => {
        const aplicaCabana = parseInt(String(p.id_cabana), 10) === id_cabana;
        const estadoPR     = String(p.estado ?? '') === 'pendiente_pago';
        const expiraTs     = parseTimestamp(p.expira_en);
        const noVencida    = expiraTs ? expiraTs > ahora : false;
        const rangoFecha   = fechaLte(p.fecha_in, fecha) && fechaGt(p.fecha_out, fecha);
        return aplicaCabana && estadoPR && noVencida && rangoFecha;
      });
      if (prereservaVigente) {
        estado               = 'ocupada';
        id_prereserva_activa = String(prereservaVigente.id_prereserva);
      }
    }

    // PASO 4B: Estado final
    if (!estado) {
      estado = tiene_checkout ? 'checkout_disponible' : 'disponible';
    }

    // Metadatos
    const tipo_dia             = getTipoDia(fecha, feriadosMap);
    const temporada            = getTemporada(fecha, temporadas);
    const hora_checkin_minima  = getHoraCheckinBase(fecha, config);
    const hora_checkin_maxima  = config.hora_checkin_max_cliente  ?? '22:00';
    const hora_checkout_maxima = config.hora_checkout_default     ?? '10:00';
    const hora_checkout_minima = config.hora_checkout_min_cliente ?? '07:00';
    const minimo_noches        = getMinNoches(config);
    const es_ultimo_dia_bloque = false;

    filasCache.push({
      id_cabana, fecha, estado,
      hora_checkin_minima, hora_checkin_maxima,
      hora_checkout_maxima, hora_checkout_minima,
      tipo_dia, temporada, es_ultimo_dia_bloque, minimo_noches,
      id_reserva_activa, id_prereserva_activa,
      tiene_checkout, id_reserva_checkout,
      tiene_checkin, id_reserva_checkin,
      recalculado_en: ahora.toISOString()
    });
  }
}

return [{
  json: {
    filasCache,
    warnings,
    source_event: inputData.source_event,
    ts_inicio:    ctx.ts_inicio,
    ts_calculo:   ahora.toISOString(),
    stats: {
      total_calculadas: filasCache.length,
      warnings:         warnings.length
    }
  }
}];

const data  = $('Motor de Cálculo').first().json;
const ahora = new Date();

const detalle = JSON.stringify({
  stats:        data.stats,
  warnings:     data.warnings,
  ts_inicio:    data.ts_inicio,
  ts_calculo:   data.ts_calculo,
  ts_escritura: ahora.toISOString()
});

return [{
  json: {
    id_log:           `LOG-DISP-${ahora.getTime()}`,
    fecha_hora:        ahora.toISOString(),
    tabla_afectada:   'DISPONIBILIDAD_CACHE',
    id_registro:      `batch_${data.stats.total_calculadas}_filas`,
    campo_modificado: 'recalculo_completo',
    valor_anterior:    '',
    valor_nuevo:       '',
    modificado_por:   'n8n',
    source_event:      data.source_event ?? 'recalculo_manual',
    nivel:             data.warnings.length > 0 ? 'warning' : 'info',
    detalle
  }
}];

const data = $('Motor de Cálculo').first().json;
return [{
  json: {
    ok:           true,
    version:      'v8',
    mensaje:      'db_recalcular_disponibilidad completado — regeneración completa',
    stats:        data.stats,
    hay_warnings: data.warnings.length > 0,
    warnings:     data.warnings,
    source_event: data.source_event
  }
}];
